async () => {
  // Force all lazy images to load by setting src from data-src and removing loading=lazy
  const imgs = Array.from(document.querySelectorAll('img[loading="lazy"]'));
  imgs.forEach(img => { img.loading = 'eager'; });

  // Scroll through the entire page to trigger lazy loading
  const pageHeight = document.body.scrollHeight;
  for (let y = 0; y <= pageHeight; y += 500) {
    window.scrollTo(0, y);
  }
  window.scrollTo(0, 0);

  // Wait for images to load
  await new Promise(resolve => setTimeout(resolve, 3000));

  const images = Array.from(document.querySelectorAll('img'));
  const results = {};
  images
    .filter(img => img.src.includes('/opt-longevity/'))
    .forEach(img => {
      const name = img.src.split('/opt-longevity/')[1];
      const rendered = img.getBoundingClientRect();
      const existing = results[name];
      if (!existing || img.naturalWidth > (existing.naturalW || 0)) {
        results[name] = {
          naturalW: img.naturalWidth,
          naturalH: img.naturalHeight,
          renderedW: Math.round(rendered.width),
          renderedH: Math.round(rendered.height)
        };
      }
    });
  return results;
}

async () => {
  await new Promise(resolve => setTimeout(resolve, 1000));
  const img = document.querySelector('img[src*="tracking-mb.png"]');
  if (!img) return null;
  const rect = img.getBoundingClientRect();
  return { naturalW: img.naturalWidth, naturalH: img.naturalHeight, renderedW: Math.round(rect.width), renderedH: Math.round(rect.height) };
}

